SB_HDR = {"apikey": SUPABASE_KEY, "Authorization": f"Bearer {SUPABASE_KEY}",
           "Content-Type": "application/json", "Prefer": "return=representation"}

def sb_get(table, q=""):
    r = _req.get(f"{SUPABASE_URL}/rest/v1/{table}" + (f"?{q}" if q else ""), headers=SB_HDR)
    r.raise_for_status(); return r.json()

def sb_post(table, data):
    r = _req.post(f"{SUPABASE_URL}/rest/v1/{table}", json=data, headers=SB_HDR)
    r.raise_for_status(); rows = r.json(); return rows[0] if isinstance(rows, list) else rows

def sb_patch(table, q, data):
    r = _req.patch(f"{SUPABASE_URL}/rest/v1/{table}?{q}", json=data,
                   headers={**SB_HDR, "Prefer": "return=minimal"})
    r.raise_for_status(); return True

def sb_delete(table, q):
    r = _req.delete(f"{SUPABASE_URL}/rest/v1/{table}?{q}", headers=SB_HDR)
    r.raise_for_status(); return True

def hash_pw(p): return base64.b64encode(p.encode()).decode()
def verify_pw(p, h): return hash_pw(p) == h

def make_token(uid, email):
    return jwt.encode({"sub": str(uid), "email": email,
                       "iat": datetime.utcnow(),
                       "exp": datetime.utcnow() + timedelta(hours=JWT_EXPIRY)},
                      SECRET_KEY, algorithm="HS256")

def require_auth(f):
    @wraps(f)
    def d(*a, **kw):
        h = request.headers.get("Authorization", "")
        if not h.startswith("Bearer "): return jsonify({"error": "Missing token"}), 401
        try:
            pl = jwt.decode(h.split(" ",1)[1], SECRET_KEY, algorithms=["HS256"])
            g.user_id = int(pl["sub"])
        except jwt.ExpiredSignatureError: return jsonify({"error": "Token expired"}), 401
        except Exception: return jsonify({"error": "Invalid token"}), 401
        return f(*a, **kw)
    return d

def ok(data=None, msg="Success", status=200):
    r = {"success": True, "message": msg}
    if data is not None: r["data"] = data
    return jsonify(r), status

def err(msg="Error", status=400): return jsonify({"success": False, "error": msg}), status

def check_co(cid):
    cos = sb_get("erp_companies", f"user_id=eq.{g.user_id}&select=id")
    return any(str(c["id"]) == str(cid) for c in cos)

def calc_gst(items, interstate):
    sub=cgst=sgst=igst=0.0
    for i in items:
        t = i["qty"]*i["rate"]; tax = t*i["gst"]/100; sub+=t
        if interstate: igst+=tax
        else: cgst+=tax/2; sgst+=tax/2
    total=sub+cgst+sgst+igst
    return {"sub":round(sub,2),"cgst":round(cgst,2),"sgst":round(sgst,2),"igst":round(igst,2),"total":round(total,2)}

