@app.post("/api/v1/companies/<int:cid>/vouchers")
@require_auth
def create_voucher(cid):
    if not check_co(cid): return err("Access denied",403)
    d=request.get_json(force=True) or {}
    vtype=d.get("type")
    if vtype not in ("sales","purchase"): return err("type must be sales or purchase",422)
    if not d.get("party_id"): return err("party_id is required",422)
    items=d.get("items",[])
    if not items: return err("At least one item is required",422)
    interstate=d.get("interstate",False)
    try:
        if vtype=="sales":
            for item in items:
                rows=sb_get("erp_stock",f"id=eq.{item['itemId']}&select=name,qty")
                if rows and float(rows[0]["qty"] or 0)<item["qty"]:
                    return err(f"Insufficient stock for '{rows[0]['name']}'. Available: {rows[0]['qty']}",400)
        tots=calc_gst(items,interstate)
        pr=sb_get("erp_ledgers",f"id=eq.{d['party_id']}&select=name")
        pname=pr[0]["name"] if pr else ""
        av=sb_get("erp_vouchers",f"company_id=eq.{cid}&type=eq.{vtype}&select=id")
        prefix="SALE" if vtype=="sales" else "PUR"
        number=f"{prefix}-{datetime.now().year}-{str(len(av)+1).zfill(5)}"
        voucher=sb_post("erp_vouchers",{"company_id":cid,"type":vtype,"number":number,"date":d.get("date",str(datetime.now().date())),"party":pname,"party_id":str(d["party_id"]),"sub":tots["sub"],"cgst":tots["cgst"],"sgst":tots["sgst"],"igst":tots["igst"],"total":tots["total"],"narration":d.get("narration",""),"items":items,"interstate":interstate})
        for item in items:
            rows=sb_get("erp_stock",f"id=eq.{item['itemId']}&select=qty")
            if rows:
                cur=float(rows[0]["qty"] or 0)
                nq=max(0,cur-item["qty"]) if vtype=="sales" else cur+item["qty"]
                sb_patch("erp_stock",f"id=eq.{item['itemId']}",{"qty":nq})
        lr=sb_get("erp_ledgers",f"id=eq.{d['party_id']}&select=balance")
        if lr: sb_patch("erp_ledgers",f"id=eq.{d['party_id']}",{"balance":float(lr[0]["balance"] or 0)+tots["total"]})
        return ok({**voucher,"totals":tots},f"{vtype.title()} voucher posted",201)
    except Exception as e: return err(str(e),500)

