@app.get("/api/v1/companies/<int:cid>/reports/dashboard")
@require_auth
def dashboard(cid):
    if not check_co(cid): return err("Access denied",403)
    try:
        vs=sb_get("erp_vouchers",f"company_id=eq.{cid}&select=type,total")
        ls=sb_get("erp_ledgers",f"company_id=eq.{cid}&select=type,balance")
        st=sb_get("erp_stock",f"company_id=eq.{cid}&select=qty,rl,sp")
        return ok({"total_sales":round(sum(float(v["total"]) for v in vs if v["type"]=="sales"),2),"total_purchases":round(sum(float(v["total"]) for v in vs if v["type"]=="purchase"),2),"total_receivable":round(sum(float(l["balance"]) for l in ls if l["type"]=="customer"),2),"total_payable":round(sum(float(l["balance"]) for l in ls if l["type"]=="supplier"),2),"low_stock_count":sum(1 for i in st if float(i["qty"] or 0)<=float(i["rl"] or 0)),"inventory_value":round(sum(float(i["qty"] or 0)*float(i["sp"] or 0) for i in st),2),"voucher_count":len(vs)})
    except Exception as e: return err(str(e),500)

